import { ComponentModule } from '@/main';
import { url } from '@/services/api.service';
import { getAuthenticatedUser } from '@/services/auth.service';

export default {
    name: () => 'avatar',
    template: () => import('./avatar.html?raw'),
    data: () => ({
        loading: false,
        img: 'https://ui-avatars.com/api/?size=1&color=fff&background=fff',
        async init() {
            console.log('avatar@init');

            const user = await getAuthenticatedUser();
            const imageUrl = url('/isiWeb/web/v1/profile-image?v=1');

            const r = await fetch(imageUrl, {
                credentials: 'include',
            });

            this.img = r.ok
                ? imageUrl
                : `https://ui-avatars.com/api/?size=48&color=ed772d&background=ffffff&name=${user.nombre}`;
        },
    }),
} as ComponentModule;
