import avatar from '@/components/shared/avatar/avatar';
import { ComponentModule, render } from '@/main';
import { logout } from '@/services/auth.service';
import { Dropdown } from 'flowbite';

export default {
    name: () => 'nav',
    template: () => import('./nav.html?raw'),
    data: () => ({
        loading: false,
        avatar: null as string | null,
        async init() {
            console.log('nav@init');
            this.avatar = await render(avatar);

            this.configureUserDropdown();
        },
        async logout() {
            console.log('nav@logout');
            await logout();
        },
        configureUserDropdown() {
            new Dropdown(this.$refs.dropdown, this.$refs.dropdownTrigger, {
                placement: 'bottom',
                triggerType: 'click',
                offsetSkidding: 0,
                offsetDistance: 10,
                delay: 300,
                ignoreClickOutsideClass: false,
                onHide: () => {
                    console.log('dropdown has been hidden');
                },
                onShow: () => {
                    console.log('dropdown has been shown');
                },
                onToggle: () => {
                    console.log('dropdown has been toggled');
                },
            });
        },
    }),
} as ComponentModule;
